395   for (const auto &[RegClass, MaxUsers] : MaxLocalUsers) {
396     unsigned AvailableRegs = OverrideMaxNumRegs > 0
397                                  ? OverrideMaxNumRegs
398                                  : Ctx.TTI.getNumberOfRegisters(RegClass);
399     if (MaxUsers > AvailableRegs) {
400       unsigned Spills = MaxUsers - AvailableRegs;
401       InstructionCost SpillCost =
402           Ctx.TTI.getRegisterClassSpillCost(RegClass, Ctx.CostKind);
403       InstructionCost TotalCost = Spills * SpillCost;
