413 SmallVector<VPRegisterUsage, 8> llvm::calculateRegisterUsageForPlan(
414     VPlan &Plan, ArrayRef<ElementCount> VFs, const TargetTransformInfo &TTI,
415     const SmallPtrSetImpl<const Value *> &ValuesToIgnore) {
416   // Each 'key' in the map opens a new interval. The values
417   // of the map are the index of the 'last seen' usage of the
418   // VPValue that is the key.
419   using IntervalMap = SmallDenseMap<VPValue *, unsigned, 16>;
420 
421   // Maps indices to recipes.
422   SmallVector<VPRecipeBase *, 64> Idx2Recipe;
423   // Marks the end of each interval.
424   IntervalMap EndPoint;
425   // Saves the list of VPValues that are used in the loop.
426   SmallPtrSet<VPValue *, 8> Ends;
427   // Saves the list of values that are used in the loop but are defined outside
428   // the loop (not including non-recipe values such as arguments and
429   // constants).
430   SmallSetVector<VPValue *, 8> LoopInvariants;
431   LoopInvariants.insert(&Plan.getVectorTripCount());
432 
433   // We scan the loop in a topological order in order and assign a number to
434   // each recipe. We use RPO to ensure that defs are met before their users. We
435   // assume that each recipe that has in-loop users starts an interval. We
436   // record every time that an in-loop value is used, so we have a list of the
437   // first occurences of each recipe and last occurrence of each VPValue.
438   VPRegionBlock *LoopRegion = Plan.getVectorLoopRegion();
439   ReversePostOrderTraversal<VPBlockDeepTraversalWrapper<VPBlockBase *>> RPOT(
440       LoopRegion);
441   for (VPBasicBlock *VPBB : VPBlockUtils::blocksOnly<VPBasicBlock>(RPOT)) {
442     if (!VPBB->getParent())
443       break;
444     for (VPRecipeBase &R : *VPBB) {
445       Idx2Recipe.push_back(&R);
446 
447       // Save the end location of each USE.
448       for (VPValue *U : R.operands()) {
449         auto *DefR = U->getDefiningRecipe();
450 
451         // Ignore non-recipe values such as arguments, constants, etc.
452         // FIXME: Might need some motivation why these values are ignored. If
453         // for example an argument is used inside the loop it will increase the
454         // register pressure (so shouldn't we add it to LoopInvariants).
455         auto *IRV = dyn_cast<VPIRValue>(U);
456         if (!DefR && (!IRV || !isa<Instruction>(IRV->getValue())))
457           continue;
458 
459         // If this recipe is outside the loop then record it and continue.
460         if (!DefR) {
461           LoopInvariants.insert(U);
462           continue;
463         }
464 
465         // Overwrite previous end points.
466         EndPoint[U] = Idx2Recipe.size();
467         Ends.insert(U);
468       }
469     }
470     if (VPBB == LoopRegion->getExiting()) {
471       // VPWidenIntOrFpInductionRecipes are used implicitly at the end of the
472       // exiting block, where their increment will get materialized eventually.
473       for (auto &R : LoopRegion->getEntryBasicBlock()->phis()) {
474         if (auto *WideIV = dyn_cast<VPWidenIntOrFpInductionRecipe>(&R)) {
475           EndPoint[WideIV] = Idx2Recipe.size();
476           Ends.insert(WideIV);
477         }
478       }
479     }
480   }
481 
482   // Saves the list of intervals that end with the index in 'key'.
483   using VPValueList = SmallVector<VPValue *, 2>;
484   SmallDenseMap<unsigned, VPValueList, 16> TransposeEnds;
485 
486   // Next, we transpose the EndPoints into a multi map that holds the list of
487   // intervals that *end* at a specific location.
488   for (auto &Interval : EndPoint)
489     TransposeEnds[Interval.second].push_back(Interval.first);
490 
491   SmallPtrSet<VPValue *, 8> OpenIntervals;
492   SmallVector<VPRegisterUsage, 8> RUs(VFs.size());
493   SmallVector<SmallMapVector<unsigned, unsigned, 4>, 8> MaxUsages(VFs.size());
494 
495   LLVM_DEBUG(dbgs() << "LV(REG): Calculating max register usage:\n");
496 
497   VPTypeAnalysis TypeInfo(Plan);
498 
499   const auto &TTICapture = TTI;
500   auto GetRegUsage = [&TTICapture](Type *Ty, ElementCount VF) -> unsigned {
501     if (Ty->isTokenTy() || !VectorType::isValidElementType(Ty) ||
502         (VF.isScalable() &&
503          !TTICapture.isElementTypeLegalForScalableVector(Ty)))
504       return 0;
505     return TTICapture.getRegUsageForType(VectorType::get(Ty, VF));
506   };
507 
508   // We scan the instructions linearly and record each time that a new interval
509   // starts, by placing it in a set. If we find this value in TransposEnds then
510   // we remove it from the set. The max register usage is the maximum register
511   // usage of the recipes of the set.
512   for (unsigned int Idx = 0, Sz = Idx2Recipe.size(); Idx < Sz; ++Idx) {
513     VPRecipeBase *R = Idx2Recipe[Idx];
514 
515     // Remove all of the VPValues that end at this location.
516     VPValueList &List = TransposeEnds[Idx];
517     for (VPValue *ToRemove : List)
518       OpenIntervals.erase(ToRemove);
519 
520     // Ignore recipes that are never used within the loop and do not have side
521     // effects.
522     if (none_of(R->definedValues(),
523                 [&Ends](VPValue *Def) { return Ends.count(Def); }) &&
524         !R->mayHaveSideEffects())
525       continue;
