7150 
7151       /// If a VPlan transform folded a recipe to one producing a single-scalar,
7152       /// but the original instruction wasn't uniform-after-vectorization in the
7153       /// legacy cost model, the legacy cost overestimates the actual cost.
7154       if (auto *RepR = dyn_cast<VPReplicateRecipe>(&R)) {
7155         if (RepR->isSingleScalar() &&
