4363 bool LoopVectorizationPlanner::isCandidateForEpilogueVectorization(
4364     ElementCount VF) const {
4365   // Cross iteration phis such as fixed-order recurrences and FMaxNum/FMinNum
4366   // reductions need special handling and are currently unsupported.
4367   if (any_of(OrigLoop->getHeader()->phis(), [&](PHINode &Phi) {
4368         if (!Legal->isReductionVariable(&Phi))
4369           return Legal->isFixedOrderRecurrence(&Phi);
4370         RecurKind Kind =
4371             Legal->getRecurrenceDescriptor(&Phi).getRecurrenceKind();
4372         return RecurrenceDescriptor::isFPMinMaxNumRecurrenceKind(Kind);
4373       }))
4374     return false;
4375 
4376   // FindLast reductions require special handling for the synthesized mask PHI
4377   // and are currently unsupported for epilogue vectorization.
4378   if (hasFindLastReductionPhi(getPlanFor(VF)))
4379     return false;
4380 
4381   // Phis with uses outside of the loop require special handling and are
4382   // currently unsupported.
4383   for (const auto &Entry : Legal->getInductionVars()) {
4384     // Look for uses of the value of the induction at the last iteration.
4385     Value *PostInc =
4386         Entry.first->getIncomingValueForBlock(OrigLoop->getLoopLatch());
4387     for (User *U : PostInc->users())
4388       if (!OrigLoop->contains(cast<Instruction>(U)))
4389         return false;
4390     // Look for uses of penultimate value of the induction.
4391     for (User *U : Entry.first->users())
4392       if (!OrigLoop->contains(cast<Instruction>(U)))
4393         return false;
4394   }
4395 
4396   // Epilogue vectorization code has not been auditted to ensure it handles
4397   // non-latch exits properly.  It may be fine, but it needs auditted and
4398   // tested.
4399   // TODO: Add support for loops with an early exit.
4400   if (OrigLoop->getExitingBlock() != OrigLoop->getLoopLatch())
4401     return false;
4402 
4403   return true;
4404 }
