4495     const SCEV *EstimatedTC = SE.getMulExpr(
4496         KnownMinTC,
4497         SE.getConstant(TCType, CM.getVScaleForTuning().value_or(1)));
4498     RemainingIterations = SE.getURemExpr(
4499         EstimatedTC, SE.getElementCount(TCType, MainLoopVF * IC));
4500   } else
4501     RemainingIterations =
4502         SE.getURemExpr(TC, SE.getElementCount(TCType, EstimatedRuntimeVF * IC));
4503 
4504   // No iterations left to process in the epilogue.
4505   if (RemainingIterations->isZero())
4506     return Result;
4507 
4508   if (MainLoopVF.isFixed()) {
4509     MaxTripCount = MainLoopVF.getFixedValue() * IC - 1;
4510     if (SE.isKnownPredicate(CmpInst::ICMP_ULT, RemainingIterations,
4511                             SE.getConstant(TCType, MaxTripCount))) {
4512       MaxTripCount = SE.getUnsignedRangeMax(RemainingIterations).getZExtValue();
4513     }
4514     LLVM_DEBUG(dbgs() << "LEV: Maximum Trip Count for Epilogue: "
4515                       << MaxTripCount << "\n");
4516   }
4517 
4518   auto SkipVF = [&](const SCEV *VF, const SCEV *RemIter) -> bool {
4519     return SE.isKnownPredicate(CmpInst::ICMP_UGT, VF, RemIter);
4520   };
4521   for (auto &NextVF : ProfitableVFs) {
4522     // Skip candidate VFs without a corresponding VPlan.
4523     if (!hasPlanWithVF(NextVF.Width))
4524       continue;
4525 
4526     // Skip candidate VFs with widths >= the (estimated) runtime VF (scalable
4527     // vectors) or > the VF of the main loop (fixed vectors).
4528     if ((!NextVF.Width.isScalable() && MainLoopVF.isScalable() &&
4529          ElementCount::isKnownGE(NextVF.Width, EstimatedRuntimeVF)) ||
4530         (NextVF.Width.isScalable() &&
4531          ElementCount::isKnownGE(NextVF.Width, MainLoopVF)) ||
4532         (!NextVF.Width.isScalable() && !MainLoopVF.isScalable() &&
4533          ElementCount::isKnownGT(NextVF.Width, MainLoopVF)))
4534       continue;
4535 
4536     // If NextVF is greater than the number of remaining iterations, the
4537     // epilogue loop would be dead. Skip such factors.
